#include<cstdio>
#include<cstring>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
#define grep(b,c) for(int c(head[b]);c;c=nxt[c])
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return flag ? -res : res ;
}
template<typename T> inline T min(const T&x,const T&y){return x<y?x:y;}
template<typename T> inline T max(const T&x,const T&y){return x<y?y:x;}
const int N=2e5+10,INF=0x3f3f3f3f;int mx[N];
int head[N],des[N<<1],nxt[N<<1],cgt,val[N<<1],n,K,siz[N],M;bool vis[N],col[N];
inline void add(int x,int w){++x;while(x<=n+1){mx[x]=max(mx[x],w);x+=(x&-x);}}
inline int qry(int x){++x;int res=~INF;while(x)res=max(res,mx[x]),x^=(x&-x);return res;}
inline void Clear(int x){++x;while(x<=n+1)mx[x]=~INF,x+=(x&-x);}
inline void ins(const int&z,const int &x,const int &y)
{
	nxt[++cgt]=head[x];des[head[x]=cgt]=y;val[cgt]=z;
	nxt[++cgt]=head[y];des[head[y]=cgt]=x;val[cgt]=z;
}
int Mn,Sz,Rt;inline void getRt(int u,int fa=0)
{
	int mx=0;siz[u]=1;grep(u,i)
	{
		int v=des[i];if(vis[v]||v==fa)continue;
		getRt(v,u);siz[u]+=siz[v];mx=max(mx,siz[v]);
	}
	mx=max(mx,Sz-siz[u]);mx<Mn?Mn=mx,Rt=u:0;
}
int RT,Ans,stk[N],top;
inline void dfs0(int u,int fa,int dis=0,int w=0)
{
	if(K-w-col[RT]<0)return;Ans=max(dis+qry(K-w),Ans);
//	printf("dfs0 %d %d %d %d %d\n",u,dis,w,qry(K-w-col[RT]),K-w-col[RT]);
	grep(u,i)
	{
		int v=des[i];if(vis[v]||v==fa)continue;
//		if(u==4&&v==3)printf("%d\n",w+col[v]);
		dfs0(v,u,dis+val[i],w+col[v]);
	}
}
inline void dfs1(int u,int fa,int dis=0,int w=0)
{
	if(w>K)return;add(stk[++top]=w+col[RT],dis);
	grep(u,i){int v=des[i];if(vis[v]||v==fa)continue;dfs1(v,u,dis+val[i],w+col[v]);}
}
inline void Cnt(int u)
{
	add(stk[++top]=col[RT=u],0);
	grep(u,i){int v=des[i];if(vis[v])continue;dfs0(v,u,val[i],col[v]);dfs1(v,u,val[i],col[v]);}
	while(top)Clear(stk[top--]);
}
inline void Solve(int u)
{	
//	printf("Solve :: ____ %d ____\n",u);
	vis[u]=true;Cnt(u);grep(u,i)
	{
		int v=des[i];if(vis[v])continue;
		Sz=siz[v];Mn=INF;Rt=0;getRt(v);Solve(Rt);
	}
}
int main()
{
//	FIN("data.in");
//	FOUT("mine.out");
	n=read();K=read();M=read();while(M--)col[read()]=true;rep(2,n,i)ins(read(),read(),read());
	memset(mx,~0x3f,sizeof(mx));Mn=INF;Sz=n;Rt=0;getRt(1);Solve(Rt);printf("%d\n",Ans);return 0;
}
